extra.modelCss:
/* Grid base: cards */

.cards {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.card {
  padding: 16px;
  border: 1px solid #ddd;
  border-radius: 14px;
}

/* Exemplo de colunas diferentes */
.layout {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 16px;
}
